class Solution {
public:
    int longestDecomposition(string text) {
        int n = text.size();
        int ans = 0;
        for (int i = 1; i <= n / 2; i++) {
            if (text.substr(0, i) == text.substr(n - i, i)) {
                ans = 2 * i;
                break;
            }
        }
        return ans;
    }
};
```

